using System.Runtime.InteropServices;
using System.Runtime.Intrinsics;

namespace ProdOp;

public static class MathOps
{
    /// <summary>Computes the product of all elements.</summary>
    public static float Product(ReadOnlySpan<float> values)
    {
        if (values.IsEmpty) return 0f;

        int i = 0;

        // SIMD path: four independent accumulators hide multiply latency
        if (Vector256.IsHardwareAccelerated && values.Length >= Vector256<float>.Count * 4)
        {
            var acc0 = Vector256<float>.One;
            var acc1 = Vector256<float>.One;
            var acc2 = Vector256<float>.One;
            var acc3 = Vector256<float>.One;

            ReadOnlySpan<Vector256<float>> vectors =
                MemoryMarshal.Cast<float, Vector256<float>>(values);

            int vi = 0;
            int unrolledEnd = vectors.Length - 3;
            while (vi < unrolledEnd)
            {
                acc0 *= vectors[vi];
                acc1 *= vectors[vi + 1];
                acc2 *= vectors[vi + 2];
                acc3 *= vectors[vi + 3];
                vi += 4;
            }

            // Remaining full vectors
            while (vi < vectors.Length)
            {
                acc0 *= vectors[vi];
                vi++;
            }

            acc0 = acc0 * acc1 * acc2 * acc3;

            // Horizontal reduce the final vector
            float product = 1f;
            for (int j = 0; j < Vector256<float>.Count; j++)
                product *= acc0[j];

            i = vectors.Length * Vector256<float>.Count;

            // Scalar tail
            for (; i < values.Length; i++)
                product *= values[i];

            return product;
        }

        if (Vector128.IsHardwareAccelerated && values.Length >= Vector128<float>.Count * 4)
        {
            var acc0 = Vector128<float>.One;
            var acc1 = Vector128<float>.One;
            var acc2 = Vector128<float>.One;
            var acc3 = Vector128<float>.One;

            ReadOnlySpan<Vector128<float>> vectors =
                MemoryMarshal.Cast<float, Vector128<float>>(values);

            int vi = 0;
            int unrolledEnd = vectors.Length - 3;
            while (vi < unrolledEnd)
            {
                acc0 *= vectors[vi];
                acc1 *= vectors[vi + 1];
                acc2 *= vectors[vi + 2];
                acc3 *= vectors[vi + 3];
                vi += 4;
            }

            while (vi < vectors.Length)
            {
                acc0 *= vectors[vi];
                vi++;
            }

            acc0 = acc0 * acc1 * acc2 * acc3;

            float product = 1f;
            for (int j = 0; j < Vector128<float>.Count; j++)
                product *= acc0[j];

            i = vectors.Length * Vector128<float>.Count;

            for (; i < values.Length; i++)
                product *= values[i];

            return product;
        }

        // Scalar fallback with 4-way unroll
        {
            float p0 = 1f, p1 = 1f, p2 = 1f, p3 = 1f;
            int end = values.Length - 3;
            for (; i < end; i += 4)
            {
                p0 *= values[i];
                p1 *= values[i + 1];
                p2 *= values[i + 2];
                p3 *= values[i + 3];
            }
            float product = p0 * p1 * p2 * p3;
            for (; i < values.Length; i++)
                product *= values[i];
            return product;
        }
    }
}

